patch:
diff --git a/llvm/lib/Transforms/IPO/GlobalOpt.cpp b/llvm/lib/Transforms/IPO/GlobalOpt.cpp
index cfba8dcc05b2..94569f08e9e6 100644
--- a/llvm/lib/Transforms/IPO/GlobalOpt.cpp
+++ b/llvm/lib/Transforms/IPO/GlobalOpt.cpp
@@ -1121,6 +1121,21 @@ static bool tryToOptimizeStoreOfAllocationToGlobal(GlobalVariable *GV,
   if (!valueIsOnlyUsedLocallyOrStoredToOneGlobal(CI, GV))
     return false;

+  // Do not attempt this optimization if any load/store of the global is
+  // atomic. The optimization introduces a tracking i1 global and emits
+  // atomic operations on it, which is invalid IR (atomic ops require a
+  // byte-sized operand). Instead of trying to widen the tracking type and
+  // adjust all logic (which is unnecessary for correctness here), just
+  // bail out and leave the original atomic accesses untouched.
+  SmallVector<Value *, 4> AtomicScan;
+  allUsesOfLoadAndStores(GV, AtomicScan);
+  for (auto *U : AtomicScan) {
+    if (auto *LI = dyn_cast<LoadInst>(U); LI && LI->isAtomic())
+      return false;
+    if (auto *SI = dyn_cast<StoreInst>(U); SI && SI->isAtomic())
+      return false;
+  }
+
   OptimizeGlobalAddressOfAllocation(GV, CI, AllocSize, InitVal, DL, TLI);
   return true;
 }

test_traj:
diff --git a/llvm/lib/Transforms/IPO/GlobalOpt.cpp b/llvm/lib/Transforms/IPO/GlobalOpt.cpp
index cfba8dcc05b2..f2acc867b296 100644
--- a/llvm/lib/Transforms/IPO/GlobalOpt.cpp
+++ b/llvm/lib/Transforms/IPO/GlobalOpt.cpp
@@ -950,12 +950,14 @@ OptimizeGlobalAddressOfAllocation(GlobalVariable *GV, CallInst *CI,
   // Update users of the allocation to use the new global instead.
   CI->replaceAllUsesWith(NewGV);

-  // If there is a comparison against null, we will insert a global bool to
-  // keep track of whether the global was initialized yet or not.
+  // If there is a comparison against null, we will insert a global byte to
+  // keep track of whether the global was initialized yet or not.  This must be
+  // at least a byte because atomic operations are not permitted on sub-byte
+  // sized types (i1).
   GlobalVariable *InitBool = new GlobalVariable(
-      Type::getInt1Ty(GV->getContext()), false, GlobalValue::InternalLinkage,
-      ConstantInt::getFalse(GV->getContext()), GV->getName() + ".init",
-      GV->getThreadLocalMode(), GV->getAddressSpace());
+      Type::getInt8Ty(GV->getContext()), false, GlobalValue::InternalLinkage,
+      ConstantInt::get(Type::getInt8Ty(GV->getContext()), 0),
+      GV->getName() + ".init", GV->getThreadLocalMode(), GV->getAddressSpace());
   bool InitBoolUsed = false;

   // Loop over all instruction uses of GV, processing them in turn.
@@ -964,10 +966,10 @@ OptimizeGlobalAddressOfAllocation(GlobalVariable *GV, CallInst *CI,
   for (auto *U : Guses) {
     if (StoreInst *SI = dyn_cast<StoreInst>(U)) {
       // The global is initialized when the store to it occurs. If the stored
-      // value is null value, the global bool is set to false, otherwise true.
+      // value is null value, the global byte is set to 0, otherwise 1.
+      bool IsNonNull = !isa<ConstantPointerNull>(SI->getValueOperand());
       auto *NewSI = new StoreInst(
-          ConstantInt::getBool(GV->getContext(), !isa<ConstantPointerNull>(
-                                                     SI->getValueOperand())),
+          ConstantInt::get(Type::getInt8Ty(GV->getContext()), IsNonNull ? 1 : 0),
           InitBool, false, Align(1), SI->getOrdering(), SI->getSyncScopeID(),
           SI->getIterator());
       NewSI->setDebugLoc(SI->getDebugLoc());
@@ -984,7 +986,7 @@ OptimizeGlobalAddressOfAllocation(GlobalVariable *GV, CallInst *CI,
         continue;
       }

-      // Replace the cmp X, 0 with a use of the bool value.
+      // Replace the cmp X, 0 with logic using the initialization byte.
       Value *LV = new LoadInst(InitBool->getValueType(), InitBool,
                                InitBool->getName() + ".val", false, Align(1),
                                LI->getOrdering(), LI->getSyncScopeID(),
@@ -995,6 +997,8 @@ OptimizeGlobalAddressOfAllocation(GlobalVariable *GV, CallInst *CI,
       // component of recomputing the predicate.
       cast<LoadInst>(LV)->setDebugLoc(LI->getDebugLoc());
       InitBoolUsed = true;
+      IRBuilder<> B(ICI);
+      Constant *Zero8 = ConstantInt::get(Type::getInt8Ty(GV->getContext()), 0);
       switch (ICI->getPredicate()) {
       default: llvm_unreachable("Unknown ICmp Predicate!");
       case ICmpInst::ICMP_ULT: // X < null -> always false
@@ -1004,13 +1008,15 @@ OptimizeGlobalAddressOfAllocation(GlobalVariable *GV, CallInst *CI,
         LV = ConstantInt::getTrue(GV->getContext());
         break;
       case ICmpInst::ICMP_ULE:
-      case ICmpInst::ICMP_EQ:
-        LV = BinaryOperator::CreateNot(LV, "notinit", ICI->getIterator());
-        cast<BinaryOperator>(LV)->setDebugLoc(ICI->getDebugLoc());
+      case ICmpInst::ICMP_EQ: // X == null -> not initialized
+        LV = B.CreateICmpEQ(LV, Zero8, "notinit");
+        cast<Instruction>(LV)->setDebugLoc(ICI->getDebugLoc());
         break;
       case ICmpInst::ICMP_NE:
-      case ICmpInst::ICMP_UGT:
-        break;  // no change.
+      case ICmpInst::ICMP_UGT: // X != null -> initialized
+        LV = B.CreateICmpNE(LV, Zero8, "isinit");
+        cast<Instruction>(LV)->setDebugLoc(ICI->getDebugLoc());
+        break;  // no change beyond cmp.
       }
       ICI->replaceAllUsesWith(LV);
       ICI->eraseFromParent();
